import { describe, it } from 'node:test'
import assert from 'node:assert/strict'

describe('helpers module: constants', () => {
  it('exports TSX constant as a string pointing to tsx binary', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.TSX, 'string', 'TSX must be a string')
    assert.ok(
      mod.TSX.includes('tsx'),
      `TSX must reference a tsx binary path, got: ${mod.TSX}`,
    )
  })

  it('exports RUN constant as a string ending with run.ts', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.RUN, 'string', 'RUN must be a string')
    assert.ok(
      mod.RUN.endsWith('run.ts'),
      `RUN must end with run.ts, got: ${mod.RUN}`,
    )
  })

  it('exports LIVE constant as a boolean', async () => {
    const mod = await import('./helpers.js')
    assert.strictEqual(typeof mod.LIVE, 'boolean', `LIVE must be a boolean, got: ${typeof mod.LIVE}`)
  })
})

describe('helpers module: run()', () => {
  it('returns object with status (number), stdout (string), stderr (string)', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.strictEqual(typeof result.status, 'number', `status must be number, got: ${typeof result.status}`)
    assert.strictEqual(typeof result.stdout, 'string', `stdout must be string, got: ${typeof result.stdout}`)
    assert.strictEqual(typeof result.stderr, 'string', `stderr must be string, got: ${typeof result.stderr}`)
  })

  it('passes env override — token absent produces NOT SET in stdout', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.ok(
      result.stdout.includes('NOT SET'),
      `expected "NOT SET" in stdout when token is empty:\n${result.stdout}`,
    )
  })

  it('accepts optional timeout in third options argument', async () => {
    const { run } = await import('./helpers.js')
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' }, { timeout: 10000 })
    assert.strictEqual(
      typeof result.status,
      'number',
      `run() with timeout option must still return a numeric status, got: ${typeof result.status}`,
    )
  })
})

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { spawnSync } from 'node:child_process'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const TSX = path.join(__dirname, '..', '..', '..', '..', 'node_modules', '.bin', 'tsx')
const RUN = path.join(__dirname, '..', 'run.ts')

function run(
  args: string[] = [],
  env: Record<string, string> = {},
): { status: number | null; stdout: string; stderr: string } {
  return spawnSync(TSX, [RUN, ...args], {
    encoding: 'utf8',
    env: { ...process.env, ...env },
  })
}

describe('status command', () => {
  it('exits 0 with no token set', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.strictEqual(result.status, 0, `expected exit 0, got ${result.status}\n${result.stderr}`)
  })

  it('stdout contains NOT SET when no token', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.ok(result.stdout.includes('NOT SET'), `expected "NOT SET" in stdout:\n${result.stdout}`)
  })

  it('stdout contains masked token when token is set', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: 'phx_supersecrettoken123' })
    assert.ok(
      result.stdout.includes('***'),
      `expected masked token "***" in stdout:\n${result.stdout}`,
    )
    assert.ok(
      !result.stdout.includes('supersecrettoken123'),
      'token value must not appear in plaintext',
    )
  })

  it('stdout is valid JSON', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.doesNotThrow(
      () => JSON.parse(result.stdout),
      `stdout is not valid JSON:\n${result.stdout}`,
    )
  })

  it('includes project_id in output', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '', POSTHOG_PROJECT_ID: '39507' })
    const parsed = JSON.parse(result.stdout) as { project_id: unknown }
    assert.ok(parsed.project_id, 'output must include project_id')
  })
})

